// // This module converts a 4-bit binary integer input to its corresponding 4-bit Binary-Coded Decimal (BCD) output. However, it incorrectly maps inputs greater than 9 to 0000 instead of the default 1010.
module top_module(
    input [3:0] int_data,
    output reg [3:0] bcd_data
);always @(int_data) begin
        case (int_data)
            0: bcd_data <= 4'b0000;
            1: bcd_data <= 4'b0001;
            2: bcd_data <= 4'b0010;
            3: bcd_data <= 4'b0011;
            4: bcd_data <= 4'b0100;
            5: bcd_data <= 4'b0101;
            6: bcd_data <= 4'b0110;
            7: bcd_data <= 4'b0111;
            8: bcd_data <= 4'b1000;
            9: bcd_data <= 4'b1001;
            default: bcd_data <= 4'b1010;
        endcase
    end
endmodule
